   284→  union Sass_Value* ADDCALL sass_value_stringify (const union Sass_Value* v, bool compressed, int precision)
   285→  {
   286→    Value_Obj val = sass_value_to_ast_node(v);
   287→    Sass_Inspect_Options options(compressed ? COMPRESSED : NESTED, precision);
   288→    std::string str(val->to_string(options));
   289→    return sass_make_qstring(str.c_str());
   290→  }
   291→
   292→  union Sass_Value* ADDCALL sass_value_op (enum Sass_OP op, const union Sass_Value* a, const union Sass_Value* b)
   293→  {
   294→
   295→    Sass::Value_Obj rv;
   296→
   297→    try {
   298→
   299→      Value_Obj lhs = sass_value_to_ast_node(a);
   300→      Value_Obj rhs = sass_value_to_ast_node(b);
   301→      struct Sass_Inspect_Options options(NESTED, 5);
   302→
   303→      // see if it's a relational expression
   304→      switch(op) {
   305→        case Sass_OP::EQ:  return sass_make_boolean(Operators::eq(lhs, rhs));
   306→        case Sass_OP::NEQ: return sass_make_boolean(Operators::neq(lhs, rhs));
   307→        case Sass_OP::GT:  return sass_make_boolean(Operators::gt(lhs, rhs));
   308→        case Sass_OP::GTE: return sass_make_boolean(Operators::gte(lhs, rhs));
   309→        case Sass_OP::LT:  return sass_make_boolean(Operators::lt(lhs, rhs));
   310→        case Sass_OP::LTE: return sass_make_boolean(Operators::lte(lhs, rhs));
   311→        case Sass_OP::AND: return ast_node_to_sass_value(lhs->is_false() ? lhs : rhs);
   312→        case Sass_OP::OR:  return ast_node_to_sass_value(lhs->is_false() ? rhs : lhs);
   313→        default: break;
   314→      }
   315→
   316→      if (sass_value_is_number(a) && sass_value_is_number(b)) {
   317→        const Number* l_n = Cast<Number>(lhs);
   318→        const Number* r_n = Cast<Number>(rhs);
   319→        rv = Operators::op_numbers(op, *l_n, *r_n, options, l_n->pstate());
   320→      }
   321→      else if (sass_value_is_number(a) && sass_value_is_color(a)) {
   322→        const Number* l_n = Cast<Number>(lhs);
   323→        // Direct HSLA operations are not supported
   324→        // All color maths will be deprecated anyway
   325→        Color_RGBA_Obj r_c = Cast<Color>(rhs)->toRGBA();
   326→        rv = Operators::op_number_color(op, *l_n, *r_c, options, l_n->pstate());
   327→      }
   328→      else if (sass_value_is_color(a) && sass_value_is_number(b)) {
   329→        // Direct HSLA operations are not supported
   330→        // All color maths will be deprecated anyway
   331→        Color_RGBA_Obj l_c = Cast<Color>(lhs)->toRGBA();
   332→        const Number* r_n = Cast<Number>(rhs);
   333→        rv = Operators::op_color_number(op, *l_c, *r_n, options, l_c->pstate());
   334→      }
   335→      else if (sass_value_is_color(a) && sass_value_is_color(b)) {
   336→        // Direct HSLA operations are not supported
   337→        // All color maths will be deprecated anyway
   338→        Color_RGBA_Obj l_c = Cast<Color>(lhs)->toRGBA();
   339→        Color_RGBA_Obj r_c = Cast<Color>(rhs)->toRGBA();
   340→        rv = Operators::op_colors(op, *l_c, *r_c, options, l_c->pstate());
   341→      }
   342→      else /* convert other stuff to string and apply operation */ {
   343→        Value* l_v = Cast<Value>(lhs);
   344→        Value* r_v = Cast<Value>(rhs);
   345→        rv = Operators::op_strings(op, *l_v, *r_v, options, l_v->pstate());
   346→      }
   347→
   348→      // ToDo: maybe we should should return null value?
   349→      if (!rv) return sass_make_error("invalid return value");
   350→
   351→      // convert result back to ast node
   352→      return ast_node_to_sass_value(rv.ptr());
   353→    }
   354→
   355→    // simply pass the error message back to the caller for now
   356→    catch (Exception::InvalidSass& e) { return sass_make_error(e.what()); }
   357→    catch (std::bad_alloc&) { return sass_make_error("memory exhausted"); }
   358→    catch (std::exception& e) { return sass_make_error(e.what()); }
   359→    catch (std::string& e) { return sass_make_error(e.c_str()); }
   360→    catch (const char* e) { return sass_make_error(e); }
   361→    catch (...) { return sass_make_error("unknown"); }
   362→  }
   363→
   364→}
